const e=[{id:"void_strike",name:"Void Strike",category:"melee",rarity:"powerful",description:"Attacking a target applies a damage multiplier that rises steadily to a max level, then is removed",wikiUrl:"https://minecraft.wiki/w/Dungeons:Void_Strike",synergy:"Any melee or ranged weapon enchanted with Void Strike grants the hero a damage multiplier that increase damage to mobs, similar to the Voided status effect. The maximum multiplier increases per tier with the highest multiplier being +600% damage for melee or +300% damage for ranged.",upgrades:{level1:"+200% max damage multiplier",level2:"+400% max damage multiplier",level3:"+600% max damage multiplier"},isSoul:!1},{id:"radiance",name:"Radiance",category:"melee",rarity:"powerful",description:"Has a 20% chance to spawn a circular area that heals you and all allies within the area.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Radiance",synergy:"Radiance creates a circular area that heals the hero and their allies. The amount of health healed inside the circle increases with each tier.",upgrades:{level1:"X health healed",level2:"1.5X health healed",level3:"2X health healed"},isSoul:!1},{id:"critical_hit",name:"Critical Hit",category:"melee",rarity:"powerful",description:"Gives you a chance to inflict critical hits dealing triple damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Critical_Hit",synergy:"A weapon enchanted with Critical Hit will have a chance to deal triple damage. This chance is increased up to 20% at tier III.",upgrades:{level1:"10% chance to trigger",level2:"15% chance to trigger",level3:"20% chance to trigger"},isSoul:!1},{id:"guarding_strike",name:"Guarding Strike",category:"melee",rarity:"powerful",description:"When you defeat a mob, you are given a temporary shield that reduces damage by 50%.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Guarding_Strike",synergy:"The shield around the player when Guarding Strike is activated. Guarding strike grants the hero the ability to activate a status effect that creates a protective shield when defeating a mob, this shield reduces incoming damage by 50%.",upgrades:{level1:"2 second shield duration",level2:"3 second shield duration",level3:"4 second shield duration"},isSoul:!1},{id:"leeching",name:"Leeching",category:"melee",rarity:"common",description:"Defeating a mob heals you a small portion of the mob's max health.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Leeching",synergy:"Any melee weapon enchanted with Leeching grants the player a small amount of health when defeating a mob using that weapon. The health restored is based on the mob's HP and may be used to determine its total HP.",upgrades:{level1:"5% of mob's max health",level2:"7% of mob's max health",level3:"9% of mob's max health"},isSoul:!1},{id:"anima_conduit_melee",name:"Anima Conduit",category:"melee",rarity:"common",description:"Each soul you absorb grants a small amount of health.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Anima_Conduit",synergy:"A ranged weapon with Anima Conduit can be used for passive healing if the hero mainly uses melee weapons or artifacts to damage mobs. It heals the hero a small percent of their max health upon absorbing a soul.",upgrades:{level1:"2% of max health per soul",level2:"4% of max health per soul",level3:"6% of max health per soul"},isSoul:!0},{id:"swirling",name:"Swirling",category:"melee",rarity:"common",description:"The last attack in a combo performs a swirling attack, damaging nearby enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Swirling",synergy:"Swirling is a powerful enchantment that will perform a tornado-like attack when a mob is hit with the final attack in a combo, dealing damage to mobs nearby. The damage dealt by Swirling increases with each tier and is based on the power level of the weapon..",upgrades:{level1:"Deals X damage",level2:"Deals 1.5X damage",level3:"Deals 2X damage"},isSoul:!1},{id:"shockwave",name:"Shockwave",category:"melee",rarity:"common",description:"The last attack in a combo launches a shockwave, damaging enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Shockwave",synergy:"Shockwave grants the hero the ability to unleash a shock wave during the finishing hit of melee combos. The damage dealt is based on the power level of the weapon and increases with each tier..",upgrades:{level1:"Deals X damage",level2:"Deals 1.5X damage",level3:"Deals 2X damage"},isSoul:!1},{id:"committed",name:"Committed",category:"melee",rarity:"common",description:"Deal increased damage against already wounded enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Committed",synergy:"Committed makes the hero's weapon deal more damage against mobs depending on how much health they've already lost. For example, if the mob has lost 50% of health and the weapon has committed 3, the next attack will deal 50% more damage.",upgrades:{level1:"0-50% bonus damage",level2:"0-75% bonus damage",level3:"0-100% bonus damage"},isSoul:!1},{id:"unchanting",name:"Unchanting",category:"melee",rarity:"powerful",description:"Deal more damage to enchanted enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Unchanting",synergy:"Unchanting causes the hero's weapon to deal more damage to enchanted mobs. The amount of bonus damage dealt increases with each tier, at the maximum tier it grants +100% bonus damage against enchanted mobs..",upgrades:{level1:"+50% bonus damage",level2:"+75% bonus damage",level3:"+100% bonus damage"},isSoul:!1},{id:"gravity_melee",name:"Gravity",category:"melee",rarity:"common",description:"This effect pulls mobs in range toward's the weapon's impact point.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Gravity",synergy:"Gravity pulls mobs towards the point of impact when attacking with a weapon. The pull duration increases with each tier; at the maximum tier, the effect lasts for two seconds..",upgrades:{level1:"1.0 second duration",level2:"1.5 second duration",level3:"2.0 second duration"},isSoul:!1},{id:"refreshment_melee",name:"Refreshment",category:"melee",rarity:"common",description:"Defeating a mob reduces your health potion's cooldown time, allowing you to heal again more quickly.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Refreshment",synergy:"Refreshment reduces the health potion's cooldown time after defeating a mob by using a melee weapon or a ranged weapon. The amount of time reduced increases with each tier.",upgrades:{level1:"1.0 second health potion cooldown",level2:"2.0 second health potion cooldown",level3:"3.0 second health potion cooldown"},isSoul:!1},{id:"enigma_resonator_melee",name:"Enigma Resonator",category:"melee",rarity:"powerful",description:"Gives a chance to deal triple damage based on the number of souls you have.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Enigma_Resonator",synergy:"Any ranged weapon or melee weapon enchanted with Enigma Resonator has a chance to deal three times more damage based on how many souls the hero currently has. The chance for Enigma Resonator to deal more damage increases with each tier.",upgrades:{level1:"0-15% chance to trigger",level2:"0-20% chance to trigger",level3:"0-25% chance to trigger"},isSoul:!0},{id:"overcharge",name:"Overcharge",category:"ranged",rarity:"powerful",description:"Continue to hold the ranged attack button to double, triple, or quadruple charge a bow, increasing its damage each time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Overcharge",synergy:"Any ranged weapon enchanted with Overcharge allows the hero to charge their bow multiple times for increased damage with the highest being octuple damage. Note that the increased damage does not apply to special arrows such as fireworks or torment arrows.",upgrades:{level1:"Can charge 2 times",level2:"Can charge 3 times",level3:"Can charge 4 times"},isSoul:!1},{id:"infinity",name:"Infinity",category:"ranged",rarity:"common",description:"Chance to immediately replenish an arrow after shooting.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Infinity",synergy:"Any ranged weapon enchanted with Infinity allows the player to not use an arrow in the quiver, and constantly use the same arrow. Infinity still works on all arrow types, such as poison arrows or torment arrows.",upgrades:{level1:"16% chance of arrow not being used",level2:"32% chance of arrow not being used",level3:"48% chance of arrow not being used"},isSoul:!1},{id:"cooldown_shot",name:"Cooldown Shot",category:"ranged",rarity:"common",description:"When you attack with a charged shot, artifact cooldowns are decreased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Cooldown_Shot",synergy:"Any ranged weapon enchanted with Cooldown Shot causes artifact cooldowns to decrease after firing a charged shot. The cooldown reduction time increases with each tier, at the maximum tier artifact cooldowns are reduced by 1.5 seconds.",upgrades:{level1:"0.5 second cooldown reduction",level2:"1.0 second cooldown reduction",level3:"1.5 second cooldown reduction"},isSoul:!1},{id:"chain_reaction",name:"Chain Reaction",category:"ranged",rarity:"powerful",description:"Has a chance to fire five arrows in all directions on impact.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Chain_Reaction",synergy:"Any ranged weapon enchanted with Chain Reaction has a chance to shoot five arrows in multiple directions when shot at a mob. The chance of it activating increases by 10% each tier, at the highest tier it has a 30% chance of triggering..",upgrades:{level1:"10% chance to trigger",level2:"20% chance to trigger",level3:"30% chance to trigger"},isSoul:!1},{id:"tempo_theft",name:"Tempo Theft",category:"ranged",rarity:"common",description:"Steals 17%, 33%, and 50% mob speed, though lower tiers actually slow mobs more but give you less speed.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Tempo_Theft",synergy:"Any ranged weapon enchanted with tempo theft allows the hero to obtain a portion of a mob's movement speed when hitting them. The portion of speed stolen increases with each tier.",upgrades:{level1:"17% stolen speed",level2:"33% stolen speed",level3:"50% stolen speed"},isSoul:!1},{id:"chilling",name:"Chilling",category:"armor",rarity:"common",description:"Emits a blast every two seconds that reduces the movement and attack speed of nearby enemies for one second.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Chilling",synergy:"Chilling emits a blast every two seconds that reduces the movement and the attack speed of all nearby enemies for one second, it also gives mobs a blue glow and snow particle effect for the duration of the debuff. The reduction amount increases with each tier, at the maximum tier mob speed is reduced by 60%..",upgrades:{level1:"-20% reduced speed",level2:"-40% reduced speed",level3:"-60% reduced speed"},isSoul:!1},{id:"potion_barrier",name:"Potion Barrier",category:"armor",rarity:"powerful",description:"Whenever you use a healing potion, you take -90% damage for a short duration.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Potion_Barrier",synergy:"Potion Barrier grants the hero a blue barrier that reduces incoming damage when they use a health potion. This effect is granted to the hero in the form of a status effect.",upgrades:{level1:"5 seconds duration",level2:"7 seconds duration",level3:"9 seconds duration"},isSoul:!1},{id:"deflect",name:"Deflect",category:"armor",rarity:"common",description:"Grants a small chance to deflect incoming projectiles.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Deflect",synergy:"Deflect grants the chance to deflect any enemy projectiles fired at the hero, negating any damage it would have done. The chance of it happening increases with each tier, with a 45% chance for Deflect to activate at the maximum tier.",upgrades:{level1:"25% chance to trigger",level2:"35% chance to trigger",level3:"45% chance to trigger"},isSoul:!1},{id:"snowball_armor",name:"Snowball",category:"armor",rarity:"common",description:"Fires a snowball at a nearby enemy every few seconds, briefly stunning it.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Snowball",synergy:"Snowball spawns a floating snowball that circles around the hero. It periodically shoots projectiles at enemies that stun them for two seconds, these projectiles always hit their target and are not stopped by terrain.",upgrades:{level1:"Triggers every 5 seconds",level2:"Triggers every 3 seconds",level3:"Triggers every second"},isSoul:!1},{id:"cowardice",name:"Cowardice",category:"armor",rarity:"powerful",description:"While you are at full HP, you deal increased ranged and melee damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Cowardice",synergy:"Cowardice grants the hero an increase in the ranged and melee damage that the hero deals when at full health. When Cowardice is activated it is indicated by a status effect of the same name being displayed on the hero's screen.",upgrades:{level1:"+20% increased ranged and melee damage",level2:"+30% increased ranged and melee damage",level3:"+40% increased ranged and melee damage"},isSoul:!1},{id:"reckless",name:"Reckless",category:"armor",rarity:"powerful",description:"Your health is decreased by 40%, but your melee damage is increased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Reckless",synergy:"Any armor enchanted with Reckless cuts the hero's health by 40% but in return, it grants the hero an increase to all melee damage. The amount of extra melee damage increases with each tier, at maximum tier reckless grants +90% melee damage..",upgrades:{level1:"+50% damage increase",level2:"+70% damage increase",level3:"+90% damage increase"},isSoul:!1},{id:"death_barter",name:"Death Barter",category:"armor",rarity:"powerful",description:"The first amount of (link to MCD:emerald article, displayed as emeralds) collected are stored and then spent to save the player from death.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Death_Barter",synergy:"Any armor enchanted with Death Barter revives the hero from death at the cost of emeralds. The base cost is 150 emeralds, and it decreases by 50 for every extra tier of the enchantment.",upgrades:{level1:"Cost 150 Emeralds",level2:"Cost 100 Emeralds",level3:"Cost 50 Emeralds"},isSoul:!1},{id:"weakening",name:"Weakening",category:"melee",rarity:"common",description:"Your attacks decrease the attack damage of all nearby enemies for five seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Weakening",synergy:"Any melee weapon or ranged weapon enchanted with Weakening grants the hero the ability to weaken enemy attacks upon hit. The damage reduction increases with each tier, with the highest being 40% damage reduction..",upgrades:{level1:"20% reduction in damage",level2:"30% reduction in damage",level3:"40% reduction in damage"},isSoul:!1},{id:"anima_conduit_ranged",name:"Anima Conduit",category:"ranged",rarity:"common",description:"Each soul you absorb grants a small amount of health.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Anima_Conduit",synergy:"A ranged weapon with Anima Conduit can be used for passive healing if the hero mainly uses melee weapons or artifacts to damage mobs. It heals the hero a small percent of their max health upon absorbing a soul.",upgrades:{level1:"4% of max health per soul",level2:"6% of max health per soul",level3:"8% of max health per soul"},isSoul:!0},{id:"ambush",name:"Ambush",category:"melee",rarity:"powerful",description:"Attacks on mobs that are not actively targeting you deal increased damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Ambush",synergy:"Any melee weapon enchanted with the Ambush deals increased damage to enemies that are not targeting the hero. The boost in damage increases by 20% with each tier, with the maximum tier granting a +60% damage bonus.",upgrades:{level1:"+20% damage",level2:"+40% damage",level3:"+60% damage"},isSoul:!1},{id:"chains",name:"Chains",category:"melee",rarity:"common",description:"Has a 30% chance to chain a cluster of mobs together and keep them bound for a short time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Chains",synergy:"Any melee weapon enchanted with Chains allows the hero to bind multiple mobs together. Although chained mobs may still attack heroes in close proximity, they are rooted in place for the duration of the effect. The duration of the effect increases with each tier, at the highest tier the effect lasts for three seconds.",upgrades:{level1:"1 second duration",level2:"2 seconds duration",level3:"3 seconds duration"},isSoul:!1},{id:"dynamo",name:"Dynamo",category:"melee",rarity:"powerful",description:"Adds damage to your next attack after you roll.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Dynamo",synergy:"Any melee weapon or ranged weapon enchanted with Dynamo increases the damage of the next attack after rolling. The effect can stack up to twenty times, and the amount of times it has been stacked is shown as a status effect.",upgrades:{level1:"+X damage",level2:"+1.25X damage",level3:"+1.5X damage"},isSoul:!1},{id:"echo",name:"Echo",category:"melee",rarity:"common",description:"Some of your attacks can be followed up by another attack in quick succession.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Echo",synergy:"When Echo is applied to an item, an automatic second attack is performed after the hero attacks, followed by a cooldown period. In this cooldown period, the hero can still perform a single attack. After the cooldown period is over, the hero is able to use echo again. The cooldown period shortens by one second for each tier, at the maximum tier the cooldown period is three seconds.",upgrades:{level1:"5 seconds cooldown",level2:"4 seconds cooldown",level3:"3 seconds cooldown"},isSoul:!1},{id:"exploding",name:"Exploding",category:"melee",rarity:"powerful",description:"Mobs explode after they are defeated.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Exploding",synergy:"Exploding causes mobs to explode one second after they are defeated, dealing damage based on their max health. The proportion of the mobs health that is converted to damage increases with each tier. Exploding is not self-triggering, which means that mobs killed using an explosion caused by the Exploding enchantment will not explode.",upgrades:{level1:"Deals 20% of enemy health as damage",level2:"Deals 40% of enemy health as damage",level3:"Deals 60% of enemy health as damage"},isSoul:!1},{id:"fire_aspect",name:"Fire Aspect",category:"melee",rarity:"common",description:"Sets mobs on fire for three seconds, dealing damage over time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Fire_Aspect",synergy:"Fire Aspect is an enchantment that causes the hero’s weapon to set mobs on fire for three seconds. The damage dealt increases with each tier. It can be found on both melee weapons and ranged weapons. The damage fire aspect deals is increased by the Fire Focus enchantment.",upgrades:{level1:"X damage per second",level2:"1.25X damage per second",level3:"1.5X damage per second"},isSoul:!1},{id:"freezing",name:"Freezing",category:"melee",rarity:"common",description:"Slows mobs after hit for three seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Freezing",synergy:"Freezing is an enchantment that reduces the attack speed of a mob after being hit. The amount of speed reduction increases with each tier, the maximum tier reduces mob speed by 50%. It can be found on melee weapons. Unlike Chilling, Freezing doesn't decrease the movement speed of mobs, it only decreases their attack speed.",upgrades:{level1:"-30% reduced speed",level2:"-40% reduced speed",level3:"-50% reduced speed"},isSoul:!1},{id:"illagers_bane",name:"Illager's Bane",category:"melee",rarity:"powerful",description:"Attacks deal extra damage to (link to MCD:Illager article, displayed as Illagers).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Illager%27s_Bane",synergy:"Illager's Bane increases the damage the hero's weapon deals against Illagers. With the maximum tier increasing damage dealt to Illagers by 45%.",upgrades:{level1:"+25% increased damage",level2:"+35% increased damage",level3:"+45% increased damage"},isSoul:!1},{id:"looting",name:"Looting",category:"melee",rarity:"common",description:"Increases the chance for mobs to drop consumables.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Looting",synergy:"Looting greatly increases the chance of mobs the hero defeats dropping consumables. The chances increase with each tier, at the highest tier the chance is increased by 300%.",upgrades:{level1:"+100% increased chance",level2:"+200% increased chance",level3:"+300% increased chance"},isSoul:!1},{id:"pain_cycle",name:"Pain Cycle",category:"melee",rarity:"powerful",description:"Attacking drains your life to grant one stack of Pain Cycle. At 5 stacks, your pain is channeled into your next attack.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Pain_Cycle",synergy:"Any melee weapon enchanted with Pain Cycle causes the hero to lose 3% of max health after attacking, creating a stack, in which if it reaches 5, the stacks are channeled into the hero's next attack with the highest being +400% damage delivered per 5 stacks. The amount of stacks the hero has accumulated is shown as a status effect.",upgrades:{level1:"Max stacks does triple damage",level2:"Max stacks does quadruple damage",level3:"Max stacks does quintuple damage"},isSoul:!1},{id:"poison_cloud",name:"Poison Cloud",category:"melee",rarity:"common",description:"Has a 30% chance to summon a poison cloud that deals damage to enemies in an area for three seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Poison_Cloud",synergy:"Poison Cloud grants the hero a 30% chance to spawn a poison cloud upon attacking, dealing damage to any mobs in it. The poison cloud despawns after three seconds. The amount of damage dealt per second in the cloud increases with each tier. The damage dealt by Poison Cloud is increased by the Poison Focus enchantment.",upgrades:{level1:"X damage per second",level2:"2X damage per second",level3:"3X damage per second"},isSoul:!1},{id:"prospector",name:"Prospector",category:"melee",rarity:"common",description:"Enemies you defeat have a higher chance of dropping (link to MCD:Emerald article, displayed as emeralds).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Prospector",synergy:"Any melee weapon, ranged weapon, or armor enchanted with Prospector increases the chance that a mob drops emeralds when killed. The chance increases with each tier, with the highest tier granting a +300% chance for mobs to drop emeralds. Prospector triggers upon any kill source, not just when a mob is defeated by the gear piece prospector is enchanted on.",upgrades:{level1:"+100% increased chance",level2:"+200% increased chance",level3:"+300% increased chance"},isSoul:!1},{id:"rampaging",name:"Rampaging",category:"melee",rarity:"common",description:"After defeating a mob, there is a 10% chance to increase your attack speed by +50% for a short time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Rampaging",synergy:"Rampaging grants the hero a 10% chance to increase attack speed by 50% for a short time after defeating a mob. The duration of this effect increases with each tier, at the maximum tier, the increased attack speed lasts for fifteen seconds.",upgrades:{level1:"5 seconds",level2:"10 seconds",level3:"15 seconds"},isSoul:!1},{id:"sharpness",name:"Sharpness",category:"melee",rarity:"powerful",description:"Makes your weapon sharper, causing it to deal more damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Sharpness",synergy:"Any melee weapon enchanted with Sharpness grants the hero increased damage and can be stacked for more damage consecutively. The damage increases by tier with the highest being 33% more damage applied. Multiple instances of Sharpness on a weapon stack multiplicatively. Two instances of Sharpness III provide a total of 77% additional damage (a factor of 1.332), and four instances of Sharpness III provide a total of 212.9% additional damage.",upgrades:{level1:"+10% damage",level2:"+21% damage",level3:"+33% damage"},isSoul:!1},{id:"smiting",name:"Smiting",category:"melee",rarity:"powerful",description:"Increases damage against the (link to MCD:Undead article, displayed as Undead).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Smiting",synergy:"Smiting increases the damage that is dealt to undead mobs. The damage boost increases by 10% with each tier, at the maximum tier the damage increase is +45%.",upgrades:{level1:"+25% increased damage",level2:"+35% increased damage",level3:"+45% increased damage"},isSoul:!1},{id:"soul_siphon",name:"Soul Siphon",category:"melee",rarity:"powerful",description:"When you hit an enemy, gain a 20% chance to grant you a bunch of extra (link to MCD:Soul article, displayed as souls).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Soul_Siphon",synergy:"Soul Siphon grants a 20% chance to grant the hero extra souls upon hitting an enemy. The amount of extra souls increases with each tier, at the maximum tier five extra souls are gained.",upgrades:{level1:"1 soul",level2:"3 souls",level3:"5 souls"},isSoul:!0},{id:"stunning",name:"Stunning",category:"melee",rarity:"common",description:"Chance to temporarily stun enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Stunning",synergy:"Any melee weapon enchanted with Stunning allows the hero to temporarily stun mobs when hitting them. The chances add 5% by tier, and at a maximum tier being 15% chance of stunning.",upgrades:{level1:"5% chance",level2:"10% chance",level3:"15% chance"},isSoul:!1},{id:"thundering",name:"Thundering",category:"melee",rarity:"powerful",description:"Has a 30% chance to summon a lightning strike that damages nearby enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Thundering",synergy:"Thundering grants a 30% chance to summon a lightning strike that damages nearby enemies when hitting a mob. The damage done by the strike increases with each tier and is based on the power level of the weapon. The damage dealt by Thundering is increased by the Lightning Focus enchantment.",upgrades:{level1:"X damage dealt by lightning",level2:"2X damage dealt by lightning",level3:"3X damage dealt by lightning"},isSoul:!1},{id:"artifact_synergy_melee",name:"Artifact Synergy",category:"melee",rarity:"powerful",description:"Whenever you use an artifact, your next attack deals bonus damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Artifact_Synergy",synergy:"Any melee weapon enchanted with Artifact Synergy grants the hero's next attack bonus damage after using an artifact. The damage increases per tier with the highest being 80% extra damage dealt.",upgrades:{level1:"Deals 40% extra damage",level2:"Deals 60% extra damage",level3:"Deals 80% extra damage"},isSoul:!1},{id:"bonus_shot",name:"Bonus Shot",category:"ranged",rarity:"common",description:"Firing a shot also fires a second shot at a nearby enemy. The second shot has reduced damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Bonus_Shot",synergy:"Bonus Shot fires a second shot at a nearby enemy when shooting a ranged weapon. The second shot always deals less damage than the primary shot. The amount of damage the second arrow deals increases with each tier, at the maximum tier the second shot deal 24% of the damage the primary shot would do. If only one mob is in proximity to the hero, Bonus Shot is not activated, making it useless against any boss that doesn't summon additional mobs.",upgrades:{level1:"10% damage per shot",level2:"17% damage per shot",level3:"24% damage per shot"},isSoul:!1},{id:"dipping_poison",name:"Dipping Poison",category:"ranged",rarity:"common",description:"When you use a health potion, you are given a quiver of Poison Arrows.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Dipping_Poison",synergy:"Any ranged weapon enchanted with Dipping Poison grants the hero poison-tipped arrows upon use of a health potion. The number of poison arrows increases with each tier, with the maximum being 12 poison arrows.",upgrades:{level1:"6 poison arrows",level2:"8 poison arrows",level3:"12 poison arrows"},isSoul:!1},{id:"dynamo_ranged",name:"Dynamo",category:"ranged",rarity:"powerful",description:"Adds damage to your next attack after you roll.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Dynamo",synergy:"Any melee weapon or ranged weapon enchanted with Dynamo increases the damage of the next attack after rolling. The effect can stack up to twenty times, and the amount of times it has been stacked is shown as a status effect.",upgrades:{level1:"+X damage",level2:"+1.25X damage",level3:"+1.5X damage"},isSoul:!1},{id:"fire_aspect_ranged",name:"Fire Aspect",category:"ranged",rarity:"common",description:"Sets mobs on fire for three seconds, dealing damage over time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Fire_Aspect",synergy:"Any ranged weapon enchanted with Fire Aspect causes the hero’s weapon to set mobs on fire for three seconds. The damage dealt increases with each tier.",upgrades:{level1:"X damage per second",level2:"1.25X damage per second",level3:"1.5X damage per second"},isSoul:!1},{id:"fuse_shot",name:"Fuse Shot",category:"ranged",rarity:"powerful",description:"Every few shots has a timed charge that explodes one second after impact, dealing 100% damage to nearby mobs.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Fuse_Shot",synergy:"Any ranged weapon enchanted with Fuse Shot allows the hero to shoot an exploding arrow with increased damage every few shots with a bow. The required amount of arrows needed to be shot before this activate decreases with each tier, at the maximum tier Fuse Shot activates every third shot that is fired.",upgrades:{level1:"Every 5th shot",level2:"Every 4th shot",level3:"Every 3rd shot"},isSoul:!1},{id:"growing",name:"Growing",category:"ranged",rarity:"common",description:"The fired shot grows in the air, dealing extra damage to distant targets.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Growing",synergy:"Any ranged weapon enchanted with Growing allows the shot arrows to grow as long as it flies, dealing great damage to further targets. The damage increases by tier with the highest being 75% more damage.",upgrades:{level1:"25% maximum damage",level2:"50% maximum damage",level3:"75% maximum damage"},isSoul:!1},{id:"levitation_shot",name:"Levitation Shot",category:"ranged",rarity:"powerful",description:"After rolling, your next attack will cause the target to levitate briefly.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Levitation_Shot",synergy:"Any ranged weapon enchanted with Levitation Shot causes mobs that are shot to levitate briefly and take fall damage after the player does a roll. The amount of fall damage increases per tier with the highest being 300% fall damage. Note: It can only affect a single mob even when hitting multiple with Multishot/Chain Reaction. The same is true for the Winter's Touch/Snow Bow and Scatter Crossbow/Harp Crossbow/Lightning Harp Crossbow.",upgrades:{level1:"100% fall damage",level2:"200% fall damage",level3:"300% fall damage"},isSoul:!1},{id:"piercing",name:"Piercing",category:"ranged",rarity:"common",description:"Fired arrows sometimes gain the piercing effect, which allows them to fly through multiple mobs.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Piercing",synergy:"Any ranged weapon enchanted with Piercing allows the shot arrow to pierce through mobs. The number of shots required for the piercing effect to activate decreases with each tier. At the maximum tier, every arrow shot pierces. Arrows that have already pierced enemies can still trigger the Ricochet and Chain Reaction enchantments if they hit additional enemies. Once an arrow Richochets, it no longer Pierces. It's difficult to tell if the original arrow continues Piercing after it triggers a Chain Reaction, but the spawned arrows do not pierce. Also, arrows do not target mobs, like the original game's enchantment, Piercing.",upgrades:{level1:"Every 3rd arrow",level2:"Every 2nd arrow",level3:"Every arrow"},isSoul:!1},{id:"poison_cloud_ranged",name:"Poison Cloud",category:"ranged",rarity:"common",description:"Has a 30% chance to summon a poison cloud that deals damage to enemies in an area for three seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Poison_Cloud",synergy:"Poison Cloud grants the hero a 30% chance to spawn a poison cloud upon attacking, dealing damage to any mobs in it. The poison cloud despawns after three seconds. The amount of damage dealt per second in the cloud increases with each tier. The damage dealt by Poison Cloud is increased by the Poison Focus enchantment.",upgrades:{level1:"X damage per second",level2:"2X damage per second",level3:"3X damage per second"},isSoul:!1},{id:"power",name:"Power",category:"ranged",rarity:"powerful",description:"Power boosts arrow damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Power",synergy:"Any ranged weapon enchanted with Power deals increased damage. The increased damage increases per tier with the highest being 33% increased damage damage.",upgrades:{level1:"+10% damage",level2:"+21% damage",level3:"+33% damage"},isSoul:!1},{id:"prospector_ranged",name:"Prospector",category:"ranged",rarity:"common",description:"Enemies you defeat have a higher chance of dropping (link to MCD:Emerald article, displayed as emeralds).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Prospector",synergy:"Any melee weapon, ranged weapon, or armor enchanted with Prospector increases the chance that a mob drops emeralds when killed. The chance increases with each tier, with the highest tier granting a +300% chance for mobs to drop emeralds. Prospector triggers upon any kill source, not just when a mob is defeated by the gear piece prospector is enchanted on.",upgrades:{level1:"+100% increased chance",level2:"+200% increased chance",level3:"+300% increased chance"},isSoul:!1},{id:"punch",name:"Punch",category:"ranged",rarity:"common",description:"Boosts arrow pushback.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Punch",synergy:"Any ranged weapon enchanted with Punch increases the pushback of shot arrows. The chances of increasing vary by tier, with the highest being 400% pushback.",upgrades:{level1:"200% pushback",level2:"300% pushback",level3:"400% pushback"},isSoul:!1},{id:"radiance_shot",name:"Radiance Shot",category:"ranged",rarity:"common",description:"Has a 50% chance to spawn a circular area that heals all allies within it.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Radiance_Shot",synergy:"Radiance creates a circular area that heals the hero and their allies. The amount of health healed inside the circle increases with each tier. For melee weapons, Radiance is categorized as Powerful and has a 20% chance to activate. For ranged weapons, Radiance Shot is categorized as Common and has a 50% chance to activate.",upgrades:{level1:"X health healed",level2:"1.5X health healed",level3:"2X health healed"},isSoul:!1},{id:"ricochet",name:"Ricochet",category:"ranged",rarity:"powerful",description:"Small chance for arrows to ricochet off mobs.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Ricochet",synergy:"Any ranged weapon enchanted with ricochet has the chance to have fired arrows bounce off mobs and target another. The chance of this occurring increases with each tier, at the maximum tier there is a 60% of ricochet activating.",upgrades:{level1:"20% chance to trigger",level2:"40% chance to trigger",level3:"60% chance to trigger"},isSoul:!1},{id:"roll_charge",name:"Roll Charge",category:"ranged",rarity:"powerful",description:"When you perform a roll, your next ranged attack within the timing window will automatically be fully charged.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Roll_Charge",synergy:"Roll Charge grants the hero a status effect when rolling that makes any arrows fired within the next few seconds be immediately charged. The duration of the automatic charging increases with each tier, at the maximum tier the effect lasts for three seconds. This enchantment does not trigger Overcharge.",upgrades:{level1:"Charged Shot for 1 Second",level2:"Charged Shot for 2 Seconds",level3:"Charged Shot for 3 Seconds"},isSoul:!1},{id:"shadow_blast",name:"Shadow Blast",category:"armor",rarity:"powerful",description:"Leaving Shadow Form triggers a powerful blast that damages nearby mobs.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Shadow_Blast",synergy:"Any armor enchanted with Shadow Blast allows the hero to create a damaging blast when leaving Shadow Form. The radius of the blast increases with each tier, at maximum tier it has a four block large blast radius.",upgrades:{level1:"2 block blast radius",level2:"3 block blast radius",level3:"4 block blast radius"},isSoul:!1},{id:"smiting_ranged",name:"Smiting",category:"ranged",rarity:"powerful",description:"Increases damage against the (link to MCD:Undead article, displayed as Undead).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Smiting",synergy:"Smiting increases the damage that is dealt to undead mobs. The damage boost increases by 10% with each tier, at the maximum tier the damage increase is +45%.",upgrades:{level1:"+25% increased damage",level2:"+35% increased damage",level3:"+45% increased damage"},isSoul:!1},{id:"supercharge",name:"Supercharge",category:"ranged",rarity:"powerful",description:"Charged shots deal more damage and have more pushback.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Supercharge",synergy:"Any ranged weapon enchanted with supercharge deals increased damage and has more pushback when charged. It cannot be obtained on crossbows, as they cannot charge their shots. The bonus damage increases with each tier, at the maximum tier it grants +40% increased charged shot damage.",upgrades:{level1:"+20% increased damage",level2:"+30% increased damage",level3:"+40% increased damage"},isSoul:!1},{id:"wild_rage",name:"Wild Rage",category:"ranged",rarity:"powerful",description:"Hitting an enemy has a chance to send it into a rage, making it hostile towards everyone.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Wild_Rage",synergy:'Wild Rage that grants the hero a chance to send a mob into a "rage" when hitting them that makes it hostile towards other hostile mobs. The chance of this activating increases with each tier, at the maximum tier it grants a 40% chance to trigger. Rage lasts less than three seconds, and the Enraged mob remains a valid target for the players, unlike mobs charmed by the Love Medallion which have the duration of 10 seconds before they die.',upgrades:{level1:"20% chance to trigger",level2:"30% chance to trigger",level3:"40% chance to trigger"},isSoul:!1},{id:"acrobat",name:"Acrobat",category:"armor",rarity:"common",description:"Reduces the cooldown time between your rolls.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Acrobat",synergy:"Acrobat reduces the cooldown time between rolls. The reduction amount increases with each tier, at the maximum tier there is a 45% reduced cooldown.",upgrades:{level1:"15% reduced cooldown",level2:"30% reduced cooldown",level3:"45% reduced cooldown"},isSoul:!1},{id:"artifact_charge",name:"Artifact Charge",category:"ranged",rarity:"powerful",description:"Whenever you use an artifact, your next few attacks become charged.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Artifact_Charge",synergy:"Any ranged weapon enchanted with Artifact Charge grants the next few attacks from the hero to be charged after using an artifact, with the next three attacks being charged as the highest upgrade. Artifact Charge cannot be found on crossbows as charged attacks cannot be performed when using crossbows.",upgrades:{level1:"Next attack charged",level2:"Next 2 attacks charged",level3:"Next 3 attacks charged"},isSoul:!1},{id:"bag_of_souls",name:"Bag of Souls",category:"armor",rarity:"common",description:"Increases the maximum number of souls that can be carried.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Bag_of_Souls",synergy:"Bag of Souls increases the number of souls a hero can carry at one time. The maximum number of souls the player can carry without Bag of Souls is 300, the amount of extra souls increases with each tier, at the maximum tier 150% extra souls can be held, for a total of 750 souls. Unlike other soul enchantments, Bag of Souls can appear on non-soul type items.",upgrades:{level1:"50% extra souls",level2:"100% extra souls",level3:"150% extra souls"},isSoul:!0},{id:"beast_boss",name:"Beast Boss",category:"armor",rarity:"powerful",description:"Your pets deal more damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Beast_Boss",synergy:"Any armor enchanted with Beast Boss boosts the damage that your pets (non-cosmetic) deal to enemies. The bonus damage increases with each tier, at the maximum tier it grants 60% increased pet damage.",upgrades:{level1:"20% increased pet damage",level2:"40% increased pet damage",level3:"60% increased pet damage"},isSoul:!1},{id:"beast_burst",name:"Beast Burst",category:"armor",rarity:"powerful",description:"Using a healing potion causes an explosion at your pets' locations, dealing damage to mobs around them.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Beast_Burst",synergy:"Any armor enchanted with Beast Burst causes any pets to emit an explosion, dealing damage to any mobs near them when the hero uses a health potion. The damage is increased with each tier, at the maximum tier the explosion deals 3x damage.",upgrades:{level1:"X explosion damage",level2:"2X explosion damage",level3:"3X explosion damage"},isSoul:!1},{id:"beast_surge",name:"Beast Surge",category:"armor",rarity:"powerful",description:"Using your health potion boosts your pets' attack and movement speed for 10 seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Beast_Surge",synergy:"Any armor enchanted with Beast Surge grants the hero's pets an increase in attack and movement speed for 10 seconds after the player uses a healing potion. The attack and speed increase per tier with the highest being +150% increase.",upgrades:{level1:"+50% pet boost",level2:"+100% pet boost",level3:"+150% pet boost"},isSoul:!1},{id:"burning",name:"Burning",category:"armor",rarity:"common",description:"Every 0.5 seconds damages all nearby enemies.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Burning",synergy:"Burning grants the hero a ring of fire that damages any mobs inside it. The damage dealt increases with each tier. The damage dealt by Burning is increased by the Fire Focus enchantment.",upgrades:{level1:"X damage",level2:"2X damage",level3:"3X damage"},isSoul:!1},{id:"busy_bee",name:"Busy Bee",category:"melee",rarity:"common",description:"Chance to summon a bee after defeating a mob, with up to 3 bees joining your side.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Busy_Bee",synergy:"Any melee weapon enchanted with busy bee has a chance to summon a bee after defeating a mob. The chance of this happening increases with each tier, at the maximum tier there is a 40% chance. The bee spawns at the point where the weapon deals damage, similar to gravity",upgrades:{level1:"20% chance to trigger",level2:"30% chance to trigger",level3:"40% chance to trigger"},isSoul:!1},{id:"electrified",name:"Electrified",category:"armor",rarity:"common",description:"Rolling zaps two nearby enemies with lightning bolts, dealing damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Electrified",synergy:"The Electrified enchantment creates lightning bolts when the hero rolls. A maximum of two nearby enemies can take damage from these bolts. The damage dealt by the bolts increase with each tier. The damage dealt by Electrified is increased by the Lightning Focus enchantment.",upgrades:{level1:"Deals X damage",level2:"Deals 2X damage",level3:"Deals 3X damage"},isSoul:!1},{id:"explorer",name:"Explorer",category:"armor",rarity:"common",description:"For every one hundred blocks explored on the map, you regain a small amount of health.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Explorer",synergy:"Explorer grants the hero the ability to regain health for every one hundred blocks explored on the map, these blocks must be unexplored, therefore the hero cannot regain health when traversing already explored areas. The amount of health regained increases with each tier, at the maximum tier 1% of the hero's maximum health is regained.",upgrades:{level1:"0.3% health regained",level2:"0.7% health regained",level3:"1.0% health regained"},isSoul:!1},{id:"lucky_explorer",name:"Lucky Explorer",category:"armor",rarity:"common",description:"Chance to spawn (link to MCD:emerald article, displayed as emeralds) with every block explored.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Lucky_Explorer",synergy:"Any armor enchanted with Lucky Explorer has a 5% chance to spawn emeralds for every block travelled by the hero. The amount of emeralds dropped are increased by tier, at the maximum tier lucky explorer can spawn five emeralds.",upgrades:{level1:"1 emerald spawned",level2:"3 emeralds spawned",level3:"5 emeralds spawned"},isSoul:!1},{id:"final_shout",name:"Final Shout",category:"armor",rarity:"powerful",description:"When your health drops below 25%, all your artifacts are used (ignoring cooldown periods).",wikiUrl:"https://minecraft.wiki/w/Dungeons:Final_Shout",synergy:"The Final Shout enchantment triggers when the hero's health falls below 25%, activating all the hero's equipped artifacts even if they're on cooldown or the hero doesn't have enough souls. Once the enchantment triggers, it cannot do so again for another 12, 10, or 8 seconds, depending on the enchantment tier. If the hero's health is below 25% after the enchantment's cooldown, it activates on taking damage again. Most artifacts do not start a new cooldown when activated this way, but those with an active duration do, such as quivers, the Enchanter's Tome, and any summoning artifacts.",upgrades:{level1:"Up to every 12th second",level2:"Up to every 10th second",level3:"Up to every 8th second"},isSoul:!1},{id:"fire_focus",name:"Fire Focus",category:"armor",rarity:"powerful",description:"The fire damage you deal is increased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Fire_Focus",synergy:"Any armor enchanted with Fire Focus grants the hero a boost in fire damage. The amount of increased fire damage rises with each tier, at the maximum tier it grants a +75% increase to fire damage.",upgrades:{level1:"+25% increased fire damage",level2:"+50% increased fire damage",level3:"+75% increased fire damage"},isSoul:!1},{id:"lightning_focus",name:"Lightning Focus",category:"armor",rarity:"powerful",description:"The lightning damage you deal is increased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Lightning_Focus",synergy:"Any armor enchanted with Lightning Focus grants the player increased lightning damage. The bonus lightning damage increases with each tier, at the maximum tier it grants +75% increased lightning damage.",upgrades:{level1:"+25% increased lightning damage",level2:"+50% increased lightning damage",level3:"+75% increased lightning damage"},isSoul:!1},{id:"poison_focus",name:"Poison Focus",category:"armor",rarity:"powerful",description:"The poison damage you deal is increased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Poison_Focus",synergy:"Any armor enchanted with Poison Focus grants the hero a boost in poison damage. The amount of bonus poison damage is increased with each tier, at the maximum tier it grants +75% increased poison damage.",upgrades:{level1:"+25% increased poison damage",level2:"+50% increased poison damage",level3:"+75% increased poison damage"},isSoul:!1},{id:"soul_focus",name:"Soul Focus",category:"armor",rarity:"powerful",description:"Increases the amount of soul damage you deal.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Soul_Focus",synergy:"Any armor enchanted with Soul Focus grants the hero increased soul damage. The boost increases with each tier, at the maximum tier it grants +30% soul damage. Soul-type damage numbers are shown in a purple color.",upgrades:{level1:"+10% increased soul damage",level2:"+20% increased soul damage",level3:"+30% increased soul damage"},isSoul:!0},{id:"fire_trail",name:"Fire Trail",category:"armor",rarity:"common",description:"Rolling creates a trail of fire behind you, which deals damage to mobs for four seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Fire_Trail",synergy:"Fire Trail gives the hero the ability to create a trail of fire behind them when they roll that damages mobs before extinguishing after four seconds. The length of the trail of fire is determined by how far the hero rolled. The amount of damage dealt by the fire increases with each tier. Fire trial is a rolling trigger, which means it is activated by the light feather artifact. The damage dealt by fire trail is increased by the Fire Focus enchantment.",upgrades:{level1:"x fire damage per second",level2:"2x fire damage per second",level3:"3x fire damage per second"},isSoul:!1},{id:"food_reserves",name:"Food Reserves",category:"armor",rarity:"common",description:"Whenever you use a healing potion, you also create random food items.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Food_Reserves",synergy:"Food reserves grants the hero the ability to spawn food items upon the use of a healing potion, even if the hero is at full health. The amount of food dropped is increased with each tier, at the maximum tier three food items are dropped.",upgrades:{level1:"1 items crafted",level2:"2 items crafted",level3:"3 items crafted"},isSoul:!1},{id:"frenzied",name:"Frenzied",category:"armor",rarity:"common",description:"While you are at less than half health, your melee and ranged attack speeds are increased.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Frenzied",synergy:"Frenzied gives the hero an increase in melee and ranged attack speed when their health drops below half. The amount of bonus attack speed increases with each tier, at the maximum tier there is a 30% attack speed.",upgrades:{level1:"+10% attack speed",level2:"+20% attack speed",level3:"+30% attack speed"},isSoul:!1},{id:"health_synergy",name:"Health Synergy",category:"armor",rarity:"common",description:"When activating any artifact, you regain a small amount of health.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Health_Synergy",synergy:"Health synergy allows the hero to regain a small portion of their maximum health upon activating any artifact. The amount of health regained increases with each tier, at the maximum tier 5% of the hero's maximum health is regained.",upgrades:{level1:"3% health regained",level2:"4% health regained",level3:"5% health regained"},isSoul:!1},{id:"life_boost",name:"Life Boost",category:"armor",rarity:"powerful",description:"Each time you respawn, your maximum health increases. Health goes back to normal after each mission.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Life_Boost",synergy:"Any armor enchanted with Life Boost grants the hero an increase to their maximum health each time they respawn. Since the hero can only respawn three times, the maximum amount of extra total health is 99%. The amount of health added after death is increased by tier with the highest being 33% extra health added.",upgrades:{level1:"11% extra health",level2:"22% extra health",level3:"33% extra health"},isSoul:!1},{id:"luck_of_the_sea",name:"Luck of the Sea",category:"armor",rarity:"powerful",description:"Increases your luck, which boosts the chance that rare drops become unique.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Luck_of_the_Sea",synergy:"Luck of the Sea grants the hero an increase in luck, which means that every rare drop has a higher chance of becoming unique. The luck increase also affects the camp merchants that sell the hero items and rewards from Daily Trials and Raid Banners. Luck of the sea does not affect artifacts as they cannot become unique. The percentage luck boost increases with each tier, at the maximum tier luck of the sea grants a 30% luck increase.",upgrades:{level1:"10% luck increase",level2:"20% luck increase",level3:"30% luck increase"},isSoul:!1},{id:"multi_roll",name:"Multi-Roll",category:"armor",rarity:"powerful",description:"Grants extra rolls.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Multi-Roll",synergy:"Any armor enchanted with multi-roll grants the hero extra rolls. When using multi-roll, the slow period after using a roll does not end until all rolls have been replenished. The amount of extra rolls increases with each tier, at the maximum tier multi-roll grants four extra rolls.",upgrades:{level1:"Grants 2 rolls",level2:"Grants 3 rolls",level3:"Grants 4 rolls"},isSoul:!1},{id:"recycler",name:"Recycler",category:"armor",rarity:"common",description:"Being hit by damage-inflicting projectiles will occasionally craft a small quiver of arrows.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Recycler",synergy:"Recycler grants the hero the ability to craft a bundle of arrows when hit by a certain number of damage-inflicting projectiles. The numbers of arrows given by the bundle depends on the ranged weapon the hero is using. The amount of projectiles needed for recycler to activate decreases with each tier, at the maximum tier it activates every tenth projectile.",upgrades:{level1:"Every 30th projectile",level2:"Every 20th projectile",level3:"Every 10th projectile"},isSoul:!1},{id:"rush",name:"Rush",category:"armor",rarity:"powerful",description:"Increases movement speed for one second after taking damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Rush",synergy:"Rush grants the hero a large boost in movement speed for one second after they take any form of damage. The percentage movement speed boost increases with each tier; at the maximum tier, it grants a +90% movement speed boost after taking damage.",upgrades:{level1:"+30% movement speed",level2:"+60% movement speed",level3:"+90% movement speed"},isSoul:!1},{id:"shadow_surge",name:"Shadow Surge",category:"armor",rarity:"powerful",description:"Mobs defeated while in Shadow Form  grant extra souls",wikiUrl:"https://minecraft.wiki/w/Dungeons:Shadow_Surge",synergy:"Shadow surge grants the hero the ability to collect extra souls per mob defeated while in shadow form. The amount of extra souls increases with each tier, at the maximum tier it grants +16 souls per mob.",upgrades:{level1:"+6 souls per mob",level2:"+12 souls per mob",level3:"+16 souls per mob"},isSoul:!0},{id:"soul_speed",name:"Soul Speed",category:"armor",rarity:"common",description:"When you gather a soul, you gain a 5% stacking movement speed boost for a short time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Soul_Speed",synergy:"Soul speed grants the hero a 5% stacking movement speed boost for a short duration after collecting a soul, this effect can stack up to five times. The duration of this movement speed boost increases with each tier, at the maximum tier it lasts seven seconds. It also grants +1 soul gathering. Soul speed is a soul enchantment, which means it can only be found on armor that have either the +50% soul gathering or +1 soul gathering perk.",upgrades:{level1:"3 seconds duration",level2:"5 seconds duration",level3:"7 seconds duration"},isSoul:!0},{id:"speed_synergy",name:"Speed Synergy",category:"armor",rarity:"common",description:"When activating any artifact, you gain +20% movement speed for a short time.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Speed_Synergy",synergy:"Speed synergy grants the hero a +20% boost in movement speed when any artifact is used. The duration of this effect increases with each tier, at the maximum tier the movement speed boost lasts for three seconds.",upgrades:{level1:"1 second duration",level2:"2 seconds duration",level3:"3 seconds duration"},isSoul:!1},{id:"surprise_gift",name:"Surprise Gift",category:"armor",rarity:"powerful",description:"Whenever you use a (link to MCD:Health Potion article, displayed as healing potion), you sometimes create random consumables.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Surprise_Gift",synergy:"Surprise gift grants the hero the ability to create random consumables when using a healing potion. The chance of surprise gift triggering increases with each tier, at maximum tier there is a 150% of it triggering. This means that at least one consumable will be created, and there is a 50% chance two will be created.",upgrades:{level1:"50% chance to trigger",level2:"100% chance to trigger",level3:"150% chance to trigger"},isSoul:!1},{id:"swiftfooted",name:"Swiftfooted",category:"armor",rarity:"common",description:"Rolling makes you move faster for three seconds.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Swiftfooted",synergy:"Swiftfooted grants the hero a boost in their movement speed after performing a roll. The boost in movement speed increases with each tier, at the maximum tier it grants a +50% movement speed boost after a roll.",upgrades:{level1:"+30% movement speed",level2:"+40% movement speed",level3:"+50% movement speed"},isSoul:!1},{id:"thorns",name:"Thorns",category:"armor",rarity:"common",description:"Whenever you take damage, you deal damage back to the attacker.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Thorns",synergy:"The thorns enchantment deals damage to attackers upon being damaged. The amount of damage returned increases by 50% with each tier, at the maximum tier it deals 200% damage back to enemy attackers. Similar to the Thorns enchantment from the base game.",upgrades:{level1:"100% Damage back",level2:"150% Damage back",level3:"200% Damage back"},isSoul:!1},{id:"multishot",name:"Multishot",category:"ranged",rarity:"common",description:"Grants the chance to fire five arrows at once.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Multishot",synergy:"Grants the chance to fire five arrows at once.",upgrades:{level1:"20% chance to trigger",level2:"30% chance to trigger",level3:"40% chance to trigger"},isSoul:!1},{id:"cooldown",name:"Cool Down",category:"armor",rarity:"common",description:"Reduces the cooldown time between uses of your artifacts.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Cooldown",synergy:"Reduces the cooldown time between uses of your artifacts.",upgrades:{level1:"-15% artifact cooldown",level2:"-27% artifact cooldown",level3:"-38% artifact cooldown"},isSoul:!1},{id:"tumblebee",name:"Tumblebee",category:"armor",rarity:"common",description:"Chance to summon a (link to MCD:bee article, displayed as bee) when you roll, with up to 3 bees joining your side.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Tumblebee",synergy:"Has a chance to summon a bee when you roll.",upgrades:{level1:"20% chance to trigger",level2:"30% chance to trigger",level3:"40% chance to trigger"},isSoul:!1},{id:"burst_bowstring",name:"Burst Bowstring",category:"ranged",rarity:"powerful",description:"Shoots nearby mobs when you roll, costing one arrow per roll. Projectiles deal 40% of a charged shot's damage.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Burst_Bowstring",synergy:"After rolling, you fire arrows in multiple directions.",upgrades:{level1:"30% damage",level2:"40% damage",level3:"50% damage"},isSoul:!1},{id:"accelerate",name:"Accelerate",category:"ranged",rarity:"common",description:"Increases attack speed for each consecutive shot. Resets one second after the attack.",wikiUrl:"https://minecraft.wiki/w/Dungeons:Accelerate",synergy:"Increases attack speed with each consecutive shot.",upgrades:{level1:"+10% max attack speed",level2:"+15% max attack speed",level3:"+20% max attack speed"},isSoul:!1},{id:"void_strike_ranged",name:"Void Strike",category:"ranged",rarity:"powerful",description:"Attacking a target applies a damage multiplier that rises steadily to a max level, then is removed",wikiUrl:"https://minecraft.wiki/w/Dungeons:Void_Strike",synergy:"Any melee or ranged weapon enchanted with Void Strike grants the hero a damage multiplier that increase damage to mobs, similar to the Voided status effect. The maximum multiplier increases per tier with the highest multiplier being +600% damage for melee or +300% damage for ranged.",upgrades:{level1:"+100% max damage multiplier",level2:"+200% max damage multiplier",level3:"+300% max damage multiplier"},isSoul:!1}];export{e as E};
